"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6020],{59922:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Constructs a new `TiltCharacter` for the given character [Model].","params":[{"name":"instance","desc":"","lua_type":"Model"},{"name":"sendRate","desc":"The rate at which tilt updates will be sent to the server.","lua_type":"number"}],"returns":[{"desc":"","lua_type":"TiltCharacter"}],"function_type":"static","source":{"line":138,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"Update","desc":"Updates the tilt of the character to the given angle.","params":[{"name":"angle","desc":"If not provided, the character will update to the previous angle.","lua_type":"number?"}],"returns":[],"function_type":"method","source":{"line":152,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_init","desc":"Initializes the tilt character with the given character [Model] and send rate, constructing the `Destroying` [Signal] and setting up the necessary joints.","params":[{"name":"instance","desc":"","lua_type":"Model"},{"name":"sendRate","desc":"","lua_type":"number"}],"returns":[],"function_type":"method","private":true,"source":{"line":203,"path":"src/Client/Classes/TiltCharacter.luau"}}],"properties":[{"name":"Instance","desc":"The character [Model] the tilt character tweens the joints of.","lua_type":"Model","source":{"line":54,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"Destroying","desc":"Fired when the tilt character\'s neck is destroyed.","lua_type":"Signal","source":{"line":59,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_trove","desc":"The [Trove] used to manage the tilt character\'s resources.","lua_type":"Trove","private":true,"source":{"line":66,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_lastAngle","desc":"The last angle the tilt character was updated to.","lua_type":"number","private":true,"source":{"line":72,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_neck","desc":"The neck [Motor6D] of the tilt character.","lua_type":"Motor6D","private":true,"source":{"line":78,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_leftShoulder","desc":"The left shoulder [Motor6D] of the tilt character.","lua_type":"Motor6D","private":true,"source":{"line":84,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_rightShoulder","desc":"The right shoulder [Motor6D] of the tilt character.","lua_type":"Motor6D","private":true,"source":{"line":90,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_toolJoint","desc":"The tool joint [Motor6D] of the tilt character.","lua_type":"Motor6D?","private":true,"source":{"line":96,"path":"src/Client/Classes/TiltCharacter.luau"}},{"name":"_tweenInfo","desc":"The [TweenInfo] used to tween the tilt character\'s joints.","lua_type":"TweenInfo","private":true,"source":{"line":102,"path":"src/Client/Classes/TiltCharacter.luau"}}],"types":[],"name":"TiltCharacter","desc":"TiltCharacter manages the tweening of an R6 character model\'s joints to visually represent the direction a character is looking.\\nIt is primarily used to replicate the tilt of other players\' characters in multiplayer scenarios, providing a more immersive \\nand dynamic gameplay experience. The class can also be applied to the local player\'s character in third-person views.\\n\\n### Core Features:\\n- **Neck and Shoulder Animation**: Tweens the neck and shoulder joints to align with the target tilt angle.\\n- **Tool Integration**: Adjusts the shoulder and tool joint positions dynamically when a tool is equipped.\\n- **Distance-Based Optimization**: Disables tilt rendering for characters that are too far from the camera to improve performance.\\n- **Smooth Transitions**: Uses [TweenService] for smooth and visually appealing joint transitions.\\n\\n### Highlights:\\n- **Dynamic Tilt Updates**: Continuously updates the character\'s tilt based on the provided angle, ensuring real-time responsiveness.\\n- **Customizable Tweening**: Leverages [TweenInfo] for flexible control over the speed and style of joint animations.\\n- **Event Integration**: Emits a `Destroying` [Signal] when the tilt character is destroyed, allowing for cleanup and additional handling.\\n\\n### Implementation Notes:\\n- The class is designed for R6 character models and relies on specific joints (`Neck`, `Left Shoulder`, `Right Shoulder`, and optionally `ToolJoint`).\\n- Ensure the character model includes these joints for the class to function properly.","realm":["Client"],"source":{"line":126,"path":"src/Client/Classes/TiltCharacter.luau"}}')}}]);